INSERT INTO vocabularies (id, vocabulary_set_id, word, pronunciation, meaning, description, example_sentence, fixed_phrase, related_words, notes, created_at, updated_at) VALUES
(1, 1, 'Ubiquitous', '/juːˈbɪk.wɪ.təs/', 'Có mặt ở khắp nơi', 'Present, appearing, or found everywhere', 'Mobile phones are ubiquitous in modern society.', 'ubiquitous presence, ubiquitous technology', 'omnipresent, pervasive, widespread', 'IELTS Band 7+', NOW(), NOW()),
(2, 1, 'Resilient', '/rɪˈzɪl.i.ənt/', 'Kiên cường, có sức chống chịu', 'Able to recover quickly from difficult conditions', 'Children are often more resilient than adults.', 'resilient economy, resilient spirit', 'tough, adaptable, strong', 'Speaking Band 8', NOW(), NOW()),
(3, 1, 'Mitigate', '/ˈmɪt.ɪ.ɡeɪt/', 'Giảm nhẹ, làm dịu bớt', 'Make less severe, serious, or painful', 'Measures to mitigate climate change are essential.', 'mitigate risk, mitigate impact', 'alleviate, reduce, ease', 'Academic vocabulary', NOW(), NOW()),
(4, 1, 'Pragmatic', '/præɡˈmæt.ɪk/', 'Thực dụng, thực tế', 'Dealing with things sensibly and realistically', 'We need a pragmatic approach to solve this.', 'pragmatic approach, pragmatic solution', 'practical, realistic, sensible', 'Business English', NOW(), NOW()),
(5, 1, 'Eloquent', '/ˈel.ə.kwənt/', 'Hùng biện, lưu loát', 'Fluent or persuasive in speaking or writing', 'She gave an eloquent speech about human rights.', 'eloquent speaker, eloquent words', 'articulate, expressive, fluent', 'Speaking Band 8+', NOW(), NOW()),
